const query = ($json.query || '').toLowerCase().trim();
const telefone = ($json.telefone || '').replace('@s.whatsapp.net', '');

// Detecta ação
let action = 'listar';
if (query.includes('eliminar') || query.includes('borrar') || query.includes('excluir') || query.includes('apagar') || query.includes('delete') || query.includes('quitar')) {
  action = 'eliminar';
} else if (query.includes('editar') || query.includes('cambiar') || query.includes('modificar') || query.includes('actualizar') || query.includes('update')) {
  action = 'editar';
}

// Remove palavras de ação para ficar só com o termo de busca
const removeWords = ['eliminar','borrar','excluir','apagar','delete','quitar','editar','cambiar','modificar','actualizar','update','puede','puedes','quiero','la','el','un','una','de','para','por','favor','registro','transaccion','transacción','gasto'];
let searchTerm = query;
removeWords.forEach(w => {
  searchTerm = searchTerm.replace(new RegExp('\\b' + w + '\\b', 'gi'), '');
});
searchTerm = searchTerm.replace(/[?!.,;:]/g, '').trim();

// Tenta extrair monto se presente (para editar)
let newMonto = null;
const montoMatch = query.match(/(\d[\d.,]+)/);
if (action === 'editar' && montoMatch) {
  newMonto = Number(montoMatch[1].replace(/\./g, '').replace(',', '.'));
}

return [{
  json: {
    action,
    searchTerm,
    newMonto,
    telefone,
    originalQuery: $json.query
  }
}];

const parsed = $node['Parsear Query'].json;
const resposta = $input.first().json;
const action = parsed.action;
const searchTerm = parsed.searchTerm;
const telefone = parsed.telefone;

// Se é apenas listar, retorna direto
if (action === 'listar') {
  return [{ json: { skip: true, mensagem: resposta.message || 'Sin transacciones.' } }];
}

// Busca a transação que melhor combina
const transacciones = resposta.transacciones || [];
if (transacciones.length === 0) {
  return [{ json: { skip: true, mensagem: `❌ No encontré transacciones para buscar "${searchTerm}".` } }];
}

// Match por descrição (case insensitive, parcial)
let match = transacciones.find(t => 
  t.descripcion && t.descripcion.toLowerCase().includes(searchTerm.toLowerCase())
);

// Se não encontrou por descrição, tenta por categoria
if (!match) {
  match = transacciones.find(t => 
    t.categoria && t.categoria.toLowerCase().includes(searchTerm.toLowerCase())
  );
}

if (!match) {
  return [{ json: { skip: true, mensagem: `🔍 No encontré una transacción que coincida con "${searchTerm}". Tus últimas transacciones son:\n\n${resposta.message || ''}` } }];
}

// Prepara o payload para a ação
const payload = {
  skip: false,
  action: action,
  transaccion_id: match.id,
  telefone: telefone,
  descripcion: match.descripcion,
  monto: match.monto
};

// Se editar, adiciona campos novos
if (action === 'editar' && parsed.newMonto) {
  payload.newMonto = parsed.newMonto;
}

return [{ json: payload }];

const resposta = $input.first().json;
if (resposta.success) {
  return [{ json: { mensagem: resposta.message || '✅ Operación completada.' } }];
}
return [{ json: { mensagem: `❌ Error: ${resposta.error || 'Error desconocido'}` } }];
